import os
from typing import Any, Dict

import modal

APP_NAME = "rate-limited-api-gateway"
DICT_NAME = "rate-limited-api-gateway-output"
SECRET_NAME = "rate-limited-api-gateway-secret"

app = modal.App(APP_NAME)

rate_limit_dict = modal.Dict.from_name(DICT_NAME, create_if_missing=True)
rate_limit_secret = modal.Secret.from_name(SECRET_NAME)


@app.cls(secrets=[rate_limit_secret])
class RateLimitedApiGateway:
    @modal.enter()
    def load_config(self) -> None:
        self.gateway_api_key = os.environ["GATEWAY_API_KEY"]
        self.rate_limit_max = int(os.environ["RATE_LIMIT_MAX"])

    def _get_counter(self, key: str) -> int:
        value = rate_limit_dict.get(key)
        return int(value) if value is not None else 0

    def _set_stats(self, total_requests: int, rate_limit_hits: int) -> None:
        rate_limit_dict.put("total_requests_processed", total_requests)
        rate_limit_dict.put("rate_limit_hits", rate_limit_hits)
        rate_limit_dict.put("gateway_status", "operational")
        rate_limit_dict.put("api_version", "v1")

    @modal.web_endpoint(method="POST")
    def handle(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        api_key = payload.get("api_key")
        if not api_key:
            return {"status": "error", "detail": "api_key is required"}

        if api_key != self.gateway_api_key:
            return {"status": "error", "detail": "invalid api_key"}

        total_requests = self._get_counter("total_requests_processed")
        rate_limit_hits = self._get_counter("rate_limit_hits")
        request_key = f"api_key:{api_key}:count"
        current_count = self._get_counter(request_key)

        if current_count >= self.rate_limit_max:
            rate_limit_hits += 1
            self._set_stats(total_requests, rate_limit_hits)
            return {
                "status": "rate_limited",
                "detail": "rate limit exceeded",
                "limit": self.rate_limit_max,
                "remaining": 0,
            }

        current_count += 1
        total_requests += 1
        rate_limit_dict.put(request_key, current_count)
        self._set_stats(total_requests, rate_limit_hits)

        return {
            "status": "ok",
            "message": "request processed",
            "count": current_count,
            "remaining": max(self.rate_limit_max - current_count, 0),
        }


@app.local_entrypoint()
def main() -> None:
    payload = {"api_key": os.environ.get("GATEWAY_API_KEY", "gateway-key-prod-2024")}
    result = RateLimitedApiGateway().handle.remote(payload)
    print(result)

